import{_ as t,o as e,c as r,a2 as l}from"./chunks/framework.Bjylvv1V.js";const u=JSON.parse('{"title":"미수금 관리","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/overdue.md","filePath":"guide/scenarios/overdue.md","lastUpdated":1771991831000}'),o={name:"guide/scenarios/overdue.md"};function s(i,a,n,d,h,c){return e(),r("div",null,[...a[0]||(a[0]=[l(`<h1 id="미수금-관리" tabindex="-1">미수금 관리 <a class="header-anchor" href="#미수금-관리" aria-label="Permalink to &quot;미수금 관리&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 약 15분 | <strong>난이도</strong>: ★★☆ | <strong>주기</strong>: 매월 수납 마감 후</p></blockquote><p>수납 기한이 지났는데도 납부하지 않은 세대를 확인하고, 독촉·법적 조치를 진행하는 프로세스입니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 미납 현황 확인       (3분)  → 미납 세대·금액 파악</span></span>
<span class="line"><span>2. 미납 집계 분석       (3분)  → 장기/단기 미납 구분</span></span>
<span class="line"><span>3. 독촉장 발송         (5분)  → 문서 생성·발송</span></span>
<span class="line"><span>4. 미수금/회계 비교     (2분)  → 수납 모듈과 회계 대사</span></span>
<span class="line"><span>5. 장기 체납 조치       (2분)  → 법적 절차 검토</span></span></code></pre></div><hr><h2 id="_1단계-미납-현황-확인-3분" tabindex="-1">1단계: 미납 현황 확인 (3분) <a class="header-anchor" href="#_1단계-미납-현황-확인-3분" aria-label="Permalink to &quot;1단계: 미납 현황 확인 (3분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/overdue.html">미납조회</a> &gt; 미납대장 (RECP5070)</p></blockquote><h3 id="절차" tabindex="-1">절차 <a class="header-anchor" href="#절차" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>미납대장 화면 진입</li><li>조회 조건 설정: <ul><li><strong>조회 기간</strong>: 수납 마감일 기준</li><li><strong>금액 범위</strong>: 필요 시 최소 금액 이상만 필터</li><li><strong>미납 기간</strong>: 1개월 / 3개월 / 6개월 이상 등</li></ul></li><li><strong>조회</strong> 실행</li><li>미납 세대 목록 확인</li></ol><h3 id="조회-옵션" tabindex="-1">조회 옵션 <a class="header-anchor" href="#조회-옵션" aria-label="Permalink to &quot;조회 옵션&quot;">​</a></h3><table tabindex="0"><thead><tr><th>옵션</th><th>설명</th></tr></thead><tbody><tr><td>최종일자만</td><td>가장 최근 미납 기준으로 조회</td></tr><tr><td>특정일자</td><td>특정 시점 기준 미납 상태 확인</td></tr><tr><td>잔액조회</td><td>현재 남은 미납 잔액 기준</td></tr></tbody></table><hr><h2 id="_2단계-미납-집계-분석-3분" tabindex="-1">2단계: 미납 집계 분석 (3분) <a class="header-anchor" href="#_2단계-미납-집계-분석-3분" aria-label="Permalink to &quot;2단계: 미납 집계 분석 (3분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/overdue.html">미납조회</a> &gt; 미납집계표 (RECP5090)</p></blockquote><h3 id="절차-1" tabindex="-1">절차 <a class="header-anchor" href="#절차-1" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>미납집계표 화면 진입</li><li>조회 조건 설정</li><li><strong>조회</strong> 실행</li><li>미납 월수별 집계 확인</li></ol><h3 id="분석-포인트" tabindex="-1">분석 포인트 <a class="header-anchor" href="#분석-포인트" aria-label="Permalink to &quot;분석 포인트&quot;">​</a></h3><ul><li>[ ] 1개월 미납 세대 수는? → 단순 지연 가능성, 다음 달 자동이체로 해소 가능</li><li>[ ] 3개월 이상 미납 세대는? → 독촉장 발송 대상</li><li>[ ] 6개월 이상 장기 미납은? → 법적 조치 검토 대상</li><li>[ ] 미납 총액이 전월 대비 증감했는가?</li></ul><hr><h2 id="_3단계-독촉장-발송-5분" tabindex="-1">3단계: 독촉장 발송 (5분) <a class="header-anchor" href="#_3단계-독촉장-발송-5분" aria-label="Permalink to &quot;3단계: 독촉장 발송 (5분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/overdue.html">미납조회</a> &gt; 독촉장/독촉대장 (RECP5080)</p></blockquote><h3 id="독촉장-종류" tabindex="-1">독촉장 종류 <a class="header-anchor" href="#독촉장-종류" aria-label="Permalink to &quot;독촉장 종류&quot;">​</a></h3><table tabindex="0"><thead><tr><th>종류</th><th>용도</th><th>대상</th></tr></thead><tbody><tr><td><strong>간단 독촉장</strong></td><td>1차 납부 안내</td><td>1~2개월 미납</td></tr><tr><td><strong>경고 독촉장</strong></td><td>법적 조치 예고</td><td>3개월 이상 미납</td></tr><tr><td><strong>최고장</strong></td><td>최종 경고 (계좌정보 포함)</td><td>장기 미납</td></tr><tr><td><strong>영수증</strong></td><td>납부 확인용</td><td>납부 시 발급</td></tr><tr><td><strong>납부확인서</strong></td><td>공식 납부 증빙</td><td>요청 시 발급</td></tr></tbody></table><h3 id="절차-2" tabindex="-1">절차 <a class="header-anchor" href="#절차-2" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>독촉장/독촉대장 화면 진입</li><li>미납 세대 선택 (복수 선택 가능)</li><li>독촉장 양식 선택</li><li><strong>출력</strong> 또는 <strong>발송</strong> 실행</li></ol><div class="tip custom-block"><p class="custom-block-title">단계적 독촉</p><p>1개월 미납 → 간단 독촉장, 3개월 → 경고 독촉장, 6개월 → 최고장 순서로 단계적 조치를 권장합니다.</p></div><hr><h2 id="_4단계-미수금-회계-비교-2분" tabindex="-1">4단계: 미수금/회계 비교 (2분) <a class="header-anchor" href="#_4단계-미수금-회계-비교-2분" aria-label="Permalink to &quot;4단계: 미수금/회계 비교 (2분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/overdue.html">미납조회</a> &gt; 미수금/회계비교 (RECP5050)</p></blockquote><p>수납 모듈의 미수금과 회계 모듈의 미수금이 일치하는지 대사합니다.</p><h3 id="절차-3" tabindex="-1">절차 <a class="header-anchor" href="#절차-3" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>미수금/회계비교 화면 진입</li><li>기준일자 설정</li><li><strong>조회</strong> 실행</li><li>수납 미수금 vs 회계 미수금 비교</li></ol><h3 id="불일치-시-원인" tabindex="-1">불일치 시 원인 <a class="header-anchor" href="#불일치-시-원인" aria-label="Permalink to &quot;불일치 시 원인&quot;">​</a></h3><table tabindex="0"><thead><tr><th>원인</th><th>해결 방법</th></tr></thead><tbody><tr><td>수납 전표 연계 누락</td><td><a href="/guide/scenarios/collection.html">수납 전표 연계</a>를 실행</td></tr><tr><td>회계 전표 직접 수정</td><td>전표관리에서 수정 내역 확인 후 조정</td></tr><tr><td>수납 취소 후 전표 미반영</td><td>해당 전표를 삭제하거나 역분개 처리</td></tr></tbody></table><hr><h2 id="_5단계-장기-체납-조치-2분" tabindex="-1">5단계: 장기 체납 조치 (2분) <a class="header-anchor" href="#_5단계-장기-체납-조치-2분" aria-label="Permalink to &quot;5단계: 장기 체납 조치 (2분)&quot;">​</a></h2><p>6개월 이상 장기 체납 세대에 대해서는 법적 절차를 검토합니다.</p><h3 id="조치-단계" tabindex="-1">조치 단계 <a class="header-anchor" href="#조치-단계" aria-label="Permalink to &quot;조치 단계&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 문자/전화 독촉 (1~2개월)</span></span>
<span class="line"><span>2. 독촉장 우편 발송 (3개월)</span></span>
<span class="line"><span>3. 내용증명 발송 (4~5개월)</span></span>
<span class="line"><span>4. 지급명령 신청 (6개월 이상)</span></span></code></pre></div><h3 id="체크리스트" tabindex="-1">체크리스트 <a class="header-anchor" href="#체크리스트" aria-label="Permalink to &quot;체크리스트&quot;">​</a></h3><ul><li>[ ] 독촉 이력이 문서로 남아 있는가? (법적 증빙용)</li><li>[ ] 전출 세대의 미수금은 이전 세대주에게 청구하고 있는가?</li><li>[ ] 장기수선충당금 미수금과 일반 관리비 미수금을 구분하고 있는가?</li></ul><div class="warning custom-block"><p class="custom-block-title">전출 세대 미수금</p><p>이사 간 세대의 미수금은 <strong>새 입주자가 아닌 이전 세대주</strong>에게 청구해야 합니다. <a href="/guide/scenarios/move-in-out.html">전출입 처리</a> 시나리오를 참고하세요.</p></div><hr><h2 id="부과-수납-미납-현황-한눈에-보기" tabindex="-1">부과/수납/미납 현황 한눈에 보기 <a class="header-anchor" href="#부과-수납-미납-현황-한눈에-보기" aria-label="Permalink to &quot;부과/수납/미납 현황 한눈에 보기&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 수납 &gt; <a href="/recp/overdue.html">미납조회</a> &gt; 부과/수납/미납현황 (RECP5040)</p></blockquote><p>세대별·동별로 부과 총액, 수납 총액, 미납 잔액을 한 화면에서 확인할 수 있습니다.</p><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="미납-금액이-실제와-달라요" tabindex="-1">미납 금액이 실제와 달라요 <a class="header-anchor" href="#미납-금액이-실제와-달라요" aria-label="Permalink to &quot;미납 금액이 실제와 달라요&quot;">​</a></h3><p><strong>원인</strong>: 수납 처리가 누락되었거나, 가수금이 적용되지 않은 경우 <strong>해결</strong>: <a href="/recp/process.html">수납처리</a>에서 해당 세대의 수납 이력을 확인하고, 가수금(RECP1051)에 미적용 건이 있는지 확인하세요.</p><h3 id="연체료가-자동-계산되지-않아요" tabindex="-1">연체료가 자동 계산되지 않아요 <a class="header-anchor" href="#연체료가-자동-계산되지-않아요" aria-label="Permalink to &quot;연체료가 자동 계산되지 않아요&quot;">​</a></h3><p><strong>원인</strong>: 연체율이 등록되지 않았거나, 연체 기준 설정이 안 된 경우 <strong>해결</strong>: <a href="/impo/basic.html">기초정보</a> &gt; 연체율등록(IMPO1050)에서 월별 연체율이 정상 등록되어 있는지 확인하세요.</p><h3 id="미수금-회계-비교에서-차이가-나요" tabindex="-1">미수금/회계 비교에서 차이가 나요 <a class="header-anchor" href="#미수금-회계-비교에서-차이가-나요" aria-label="Permalink to &quot;미수금/회계 비교에서 차이가 나요&quot;">​</a></h3><p><strong>원인</strong>: 수납 전표 연계 누락, 회계 전표 직접 수정, 수납 취소 후 미반영 등 <strong>해결</strong>: 수납 전표 연계를 다시 실행하고, 전표관리에서 수정 이력(ACCT2054)을 확인하세요.</p><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/recp/process.html">수납처리</a> - 미납 세대 수납</li><li><a href="/recp/overdue.html">미납조회</a> - 미납 현황 상세</li><li><a href="/recp/auto-transfer.html">자동이체수납</a> - 자동이체 결과 확인</li><li><a href="/acct/voucher.html">전표관리</a> - 회계 전표 확인</li><li><a href="/guide/scenarios/move-in-out.html">전출입 처리</a> - 전출 세대 미수금</li></ul>`,58)])])}const b=t(o,[["render",s]]);export{u as __pageData,b as default};
